import React from 'react'

const Tasks = () => {
  return (
    <div className='task-page'>
      <div className='task-header'>
        <div><input className='task-name'/></div>
        <div><button className='task-add'>Add</button></div>
      </div>
      <div>

      </div>
      <Stylesheet/>
    </div>
  )
}

const Stylesheet=()=>{
  return <style>{`
    .task-header{
        display:flex;
        align-items:center;
        justify-content:center;
        gap:5%;
        background-color:yellow;
    }
    .task-page{
        padding:2rem;
    }
    .task-name{
       background-color:var(--secondary-color);
    }
  `}</style>
}

export default Tasks
